func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	orderIndices := make([]int, nOrders)
	for i := range orderIndices {
		orderIndices[i] = i
	}
	type FeasibleSlot struct {
		assignIdx int
		costInc   float64
		ok        bool
	}
	bestSlots := make([]FeasibleSlot, nOrders)
	secondBestSlots := make([]FeasibleSlot, nOrders)
	insertedCount := 0
	maxTries := dispatch.AssignsLen + nOrders
	if maxTries > MAXASSIGNS {
		maxTries = MAXASSIGNS
	}
	for attempt := 0; attempt < maxTries && insertedCount < nOrders; attempt++ {
		regretMax := -1.0
		selectedOrder := -1
		for _, oi := range orderIndices {
			if oris[oi].ReqCode == -1 {
				continue
			}
			bestSlots[oi] = FeasibleSlot{-1, 1e100, false}
			secondBestSlots[oi] = FeasibleSlot{-1, 1e100, false}
			bestCostInc := 1e100
			secondCostInc := 1e100
			for ai := 0; ai < dispatch.AssignsLen; ai++ {
				oldCost := dispatch.Assigns[ai].Cost
				if !dispatch.Assigns[ai].AddShip(total_ship+oi, oris[oi], dess[oi]) {
					dispatch.Assigns[ai].Cost = oldCost
					continue
				}
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost < 0 {
					dispatch.Assigns[ai].RemoveShip(total_ship + oi)
					dispatch.Assigns[ai].GenRoute()
					dispatch.Assigns[ai].Cost = oldCost
					continue
				}
				costInc := newCost - oldCost
				if costInc < bestCostInc {
					secondCostInc = bestCostInc
					secondBestSlots[oi] = bestSlots[oi]
					bestCostInc = costInc
					bestSlots[oi] = FeasibleSlot{ai, costInc, true}
				} else if costInc < secondCostInc {
					secondCostInc = costInc
					secondBestSlots[oi] = FeasibleSlot{ai, costInc, true}
				}
				dispatch.Assigns[ai].RemoveShip(total_ship + oi)
				dispatch.Assigns[ai].GenRoute()
				dispatch.Assigns[ai].Cost = oldCost
			}
			if bestSlots[oi].ok {
				regretVal := secondBestSlots[oi].costInc - bestSlots[oi].costInc
				if regretVal > regretMax || selectedOrder == -1 {
					regretMax = regretVal
					selectedOrder = oi
				}
			}
		}
		if selectedOrder == -1 {
			for oi := range orderIndices {
				if oris[oi].ReqCode != -1 {
					fallbackInserted := false
					for ai := 0; ai <= dispatch.AssignsLen; ai++ {
						if ai == dispatch.AssignsLen {
							if dispatch.AssignsLen >= MAXASSIGNS {
								break
							}
							dispatch.Assigns[ai].Cost = 0
							dispatch.Assigns[ai].StationsLen = 0
						}
						if dispatch.Assigns[ai].AddShip(total_ship+oi, oris[oi], dess[oi]) {
							dispatch.Assigns[ai].GenRoute()
							if dispatch.Assigns[ai].Cost >= 0 {
								if ai >= dispatch.AssignsLen {
									dispatch.AssignsLen++
								}
								oris[oi].ReqCode = -1
								insertedCount++
								fallbackInserted = true
								break
							} else {
								dispatch.Assigns[ai].RemoveShip(total_ship + oi)
								dispatch.Assigns[ai].GenRoute()
								dispatch.Assigns[ai].Cost = 0
							}
						}
					}
					if !fallbackInserted {
						oris[oi].ReqCode = -1
					}
				}
			}
			break
		}
		slot := bestSlots[selectedOrder]
		if dispatch.Assigns[slot.assignIdx].AddShip(total_ship+selectedOrder, oris[selectedOrder], dess[selectedOrder]) {
			dispatch.Assigns[slot.assignIdx].GenRoute()
			oris[selectedOrder].ReqCode = -1
			insertedCount++
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

